  "inlineSchema": "// Debate Tournament Management API — data model\n// British Parliamentary (BP) format: 4 teams per room (OG, OO, CG, CO),\n// each round ranks teams 1st-4th, which maps to 3/2/1/0 team points.\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\nenum Role {\n  ADMIN\n  ADJUDICATOR\n  DEBATER\n}\n\nenum BPPosition {\n  OG // Opening Government\n  OO // Opening Opposition\n  CG // Closing Government\n  CO // Closing Opposition\n}\n\nmodel User {\n  id           String   @id @default(uuid())\n  email        String   @unique\n  passwordHash String\n  name         String\n  role         Role     @default(DEBATER)\n  createdAt    DateTime @default(now())\n\n  adjudicatorRounds RoundAdjudicator[]\n  debater           Debater?\n}\n\nmodel Tournament {\n  id        String   @id @default(uuid())\n  name      String\n  location  String?\n  startDate DateTime\n  endDate   DateTime\n  breakSize Int      @default(8) // number of teams that advance to elimination rounds\n  createdAt DateTime @default(now())\n\n  teams  Team[]\n  rounds Round[]\n}\n\nmodel Team {\n  id           String     @id @default(uuid())\n  name         String\n  tournament   Tournament @relation(fields: [tournamentId], references: [id], onDelete: Cascade)\n  tournamentId String\n\n  debaters    Debater[]\n  assignments RoundTeam[]\n\n  @@unique([tournamentId, name])\n}\n\nmodel Debater {\n  id     String  @id @default(uuid())\n  userId String? @unique\n  user   User?   @relation(fields: [userId], references: [id])\n  name   String\n\n  team   Team?   @relation(fields: [teamId], references: [id])\n  teamId String?\n}\n\nmodel Motion {\n  id        String  @id @default(uuid())\n  text      String\n  infoSlide String?\n\n  round Round?\n}\n\nmodel Round {\n  id            String     @id @default(uuid())\n  tournament    Tournament @relation(fields: [tournamentId], references: [id], onDelete: Cascade)\n  tournamentId  String\n  roundNumber   Int\n  isElimination Boolean    @default(false)\n\n  motion   Motion? @relation(fields: [motionId], references: [id])\n  motionId String? @unique\n\n  teams        RoundTeam[]\n  adjudicators RoundAdjudicator[]\n\n  @@unique([tournamentId, roundNumber])\n}\n\n// A team's position and result within a specific round.\nmodel RoundTeam {\n  id       String     @id @default(uuid())\n  round    Round      @relation(fields: [roundId], references: [id], onDelete: Cascade)\n  roundId  String\n  team     Team       @relation(fields: [teamId], references: [id], onDelete: Cascade)\n  teamId   String\n  position BPPosition\n\n  rank       Int? // 1-4, set once ballots are submitted\n  speakerPts Int? // sum of speaker scores for the team in this round\n  teamPoints Int? // derived: 3/2/1/0 based on rank\n\n  @@unique([roundId, teamId])\n  @@unique([roundId, position])\n}\n\nmodel RoundAdjudicator {\n  id      String  @id @default(uuid())\n  round   Round   @relation(fields: [roundId], references: [id], onDelete: Cascade)\n  roundId String\n  user    User    @relation(fields: [userId], references: [id])\n  userId  String\n  isChair Boolean @default(false)\n\n  @@unique([roundId, userId])\n}\n",
